  "inlineSchema": "// backend/prisma/schema.prisma\n\n// 1. Database Connection \ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\n// 2. Roles (User lge types)\nenum UserRole {\n  ADMIN // Company Admin\n  MANAGER\n  TECHNICIAN\n  OCCUPANT\n}\n\n// 3. Tenant (Company / Organization) - SaaS project nisa meka godak wadagath\nmodel Tenant {\n  id        String   @id @default(uuid())\n  name      String\n  domain    String?  @unique // e.g., company-a.fms.com\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  users      User[]\n  assets     Asset[]\n  workOrders WorkOrder[]\n\n  @@index([createdAt])\n}\n\n// 4. Users table\nmodel User {\n  id        String   @id @default(uuid())\n  email     String   @unique\n  password  String\n  firstName String\n  lastName  String\n  role      UserRole @default(OCCUPANT)\n\n  // Me User aithi mona Company ekatada? (Tenant Link)\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  assignedWorkOrders WorkOrder[] @relation(\"AssignedWorkOrders\")\n\n  @@index([tenantId])\n  @@index([role])\n  @@index([createdAt])\n}\n\n// 5. Asset Status\nenum AssetStatus {\n  ACTIVE\n  INACTIVE\n  MAINTENANCE\n  RETIRED\n}\n\n// 6. Assets (Badu bhanda)\nmodel Asset {\n  id       String      @id @default(uuid())\n  name     String\n  category String\n  serialNo String?\n  status   AssetStatus @default(ACTIVE)\n\n  // Asset eka aithi Tenant ekata\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  workOrders WorkOrder[]\n\n  @@unique([tenantId, serialNo])\n  @@index([tenantId])\n  @@index([status])\n  @@index([category])\n}\n\n// 7. Work Order Status\nenum WorkOrderStatus {\n  OPEN\n  IN_PROGRESS\n  ON_HOLD\n  COMPLETED\n  CANCELLED\n}\n\n// 8. Work Order Priority\nenum WorkOrderPriority {\n  LOW\n  MEDIUM\n  HIGH\n  URGENT\n}\n\n// 9. Work Orders \nmodel WorkOrder {\n  id          String            @id @default(uuid())\n  title       String\n  description String?\n  status      WorkOrderStatus   @default(OPEN)\n  priority    WorkOrderPriority @default(MEDIUM)\n\n  // Relations\n  assetId String\n  asset   Asset  @relation(fields: [assetId], references: [id], onDelete: Cascade)\n\n  tenantId String\n  tenant   Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  assignedToId String? // Technician ගේ ID එක\n  assignedTo   User?   @relation(\"AssignedWorkOrders\", fields: [assignedToId], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([tenantId])\n  @@index([assetId])\n  @@index([status])\n  @@index([priority])\n  @@index([createdAt])\n  @@index([assignedToId])\n}\n",
